<template>
  <div class="tool-section" data-tool="worldbookEntry">
    <!-- 工具头部 -->
    <div
      class="section-header"
      style="
        display: flex;
        justify-content: space-between;
        align-items: center;
        padding: 15px 20px;
        background: linear-gradient(135deg, #2a3a4a 0%, #3a4a5a 100%);
        border-radius: 12px;
        margin-bottom: 15px;
        border: 1px solid rgba(84, 107, 131, 0.3);
        cursor: pointer;
        transition: all 0.3s ease;
      "
      @click="expanded = !expanded"
    >
      <h4
        style="margin: 0; color: #fff; font-size: 16px; font-weight: 600; display: flex; align-items: center; gap: 10px"
      >
        <i class="fa-solid fa-book-atlas" style="color: #ffc107; font-size: 18px"></i>
        世界书条目生成工具
      </h4>
      <i
        :class="expanded ? 'fa-solid fa-chevron-up' : 'fa-solid fa-chevron-down'"
        style="color: #ccc; font-size: 14px"
      ></i>
    </div>

    <div v-if="expanded" class="tool-content">
      <div class="tool-instructions">
        <p style="margin: 0 0 8px 0; color: #ccc; font-size: 12px">
          <i class="fa-solid fa-info-circle" style="margin-right: 6px; color: #ffc107"></i>
          输入你想要的世界书条目描述，AI 将自动生成符合格式的条目，并可插入到指定世界书中。
        </p>
      </div>

      <!-- 输入描述 -->
      <div class="form-group" style="margin: 15px 0">
        <label style="display: block; margin-bottom: 8px; color: #ccc; font-size: 13px; font-weight: 500">
          条目描述：
        </label>
        <textarea
          v-model="description"
          placeholder="描述你需要的世界书条目，例如：魔法学院的历史背景和规则..."
          style="
            width: 100%;
            height: 100px;
            padding: 12px;
            background: #2a2a2a;
            border: 1px solid #3a3a3a;
            border-radius: 6px;
            color: #e0e0e0;
            font-size: 13px;
            resize: vertical;
            font-family: inherit;
          "
        ></textarea>
      </div>

      <!-- 目标世界书选择 -->
      <div class="form-group" style="margin: 15px 0">
        <label style="display: block; margin-bottom: 8px; color: #ccc; font-size: 13px; font-weight: 500">
          目标世界书：
        </label>
        <select
          v-model="selectedWorldbook"
          style="
            width: 100%;
            padding: 10px;
            background: #2a2a2a;
            border: 1px solid #3a3a3a;
            border-radius: 6px;
            color: #e0e0e0;
            font-size: 13px;
          "
        >
          <option value="">选择要插入的世界书...</option>
          <option v-for="wb in availableWorldbooks" :key="wb" :value="wb">{{ wb }}</option>
        </select>
      </div>

      <!-- 进度条 -->
      <div v-if="isProcessing && progress > 0" style="margin: 15px 0">
        <div style="width: 100%; height: 10px; background: #2a2a2a; border-radius: 5px; overflow: hidden">
          <div
            :style="{
              width: progress + '%',
              height: '100%',
              background: 'linear-gradient(90deg, #ffc107, #ff9800)',
              transition: 'width 0.3s',
            }"
          ></div>
        </div>
        <p style="margin: 5px 0 0 0; color: #ffc107; font-size: 12px; text-align: center">
          生成中... {{ progress.toFixed(0) }}%
        </p>
      </div>

      <!-- 按钮 -->
      <div class="button-group" style="display: flex; gap: 10px; margin-bottom: 20px; flex-wrap: wrap">
        <button
          :disabled="isProcessing || !description.trim()"
          style="
            padding: 10px 18px;
            background: #3b82f6;
            border: none;
            border-radius: 6px;
            color: white;
            font-size: 14px;
            font-weight: 500;
            cursor: pointer;
            display: flex;
            align-items: center;
            gap: 6px;
          "
          @click="handleGenerate"
        >
          <i class="fa-solid fa-magic"></i>
          {{ isProcessing ? '生成中...' : '生成条目' }}
        </button>
        <button
          style="
            padding: 10px 18px;
            background: rgba(30, 41, 59, 0.5);
            border: 1px solid #4a4a4a;
            border-radius: 6px;
            color: #e0e0e0;
            font-size: 14px;
            cursor: pointer;
          "
          @click="clearForm"
        >
          <i class="fa-solid fa-trash" style="margin-right: 4px"></i>
          清空
        </button>
      </div>

      <!-- 输出区域 -->
      <div v-if="output" class="output-section">
        <h5 style="margin: 0 0 12px 0; color: #fff; font-size: 14px; font-weight: 600">
          <i class="fa-solid fa-check-circle" style="margin-right: 6px; color: #28a745"></i>
          生成的条目：
        </h5>

        <div
          style="background: #1e1e1e; border: 1px solid #3a3a3a; border-radius: 6px; padding: 15px; margin-bottom: 12px"
        >
          <div style="margin-bottom: 10px">
            <span style="color: #888; font-size: 12px">条目名称：</span>
            <span style="color: #ffc107; font-size: 14px; font-weight: 500">{{ output.name || '未命名' }}</span>
          </div>
          <div style="margin-bottom: 10px">
            <span style="color: #888; font-size: 12px">关键词：</span>
            <span style="color: #10b981; font-size: 12px">{{ (output.strategy?.keys || []).join(', ') || '无' }}</span>
          </div>
          <div>
            <span style="color: #888; font-size: 12px">内容：</span>
            <div
              style="
                color: #e0e0e0;
                font-size: 13px;
                line-height: 1.6;
                white-space: pre-wrap;
                margin-top: 6px;
                max-height: 200px;
                overflow-y: auto;
              "
            >
              {{ output.content || '' }}
            </div>
          </div>
        </div>

        <div style="display: flex; gap: 10px; flex-wrap: wrap">
          <button
            style="
              padding: 8px 16px;
              background: rgba(30, 41, 59, 0.5);
              border: 1px solid #4a4a4a;
              border-radius: 6px;
              color: #e0e0e0;
              font-size: 12px;
              cursor: pointer;
            "
            @click="copyResult"
          >
            <i class="fa-solid fa-copy" style="margin-right: 6px"></i>复制
          </button>
          <button
            v-if="selectedWorldbook"
            :disabled="isInserting"
            style="
              padding: 8px 16px;
              background: #10b981;
              border: none;
              border-radius: 6px;
              color: white;
              font-size: 12px;
              cursor: pointer;
            "
            @click="insertToWorldbook"
          >
            <i class="fa-solid fa-download" style="margin-right: 6px"></i>
            {{ isInserting ? '插入中...' : '插入到世界书' }}
          </button>
        </div>
      </div>
    </div>
  </div>
</template>

<script setup lang="ts">
import { storeToRefs } from 'pinia';
import { ref, watch } from 'vue';
import { useSettingsStore } from '../../settings';
import { copyToClipboard } from '../../utils';
import { callAIWithTavernSupport } from '../../utils/api';
import { translateError } from '../../utils/error-handler';

const settingsStore = useSettingsStore();
const { settings } = storeToRefs(settingsStore);

interface WorldbookEntry {
  name: string;
  content: string;
  strategy?: {
    type: string;
    keys: string[];
    secondary_keys?: string[];
  };
}

const props = defineProps<{ availableWorldbooks: string[] }>();
const emit = defineEmits<{ (e: 'dataChange', data: any): void }>();

const expanded = ref(true);
const description = ref('');
const output = ref<WorldbookEntry | null>(null);
const selectedWorldbook = ref('');
const isProcessing = ref(false);
const isInserting = ref(false);
const progress = ref(0);

watch(
  [description, output, selectedWorldbook],
  () => {
    emit('dataChange', {
      description: description.value,
      output: output.value,
      selectedWorldbook: selectedWorldbook.value,
    });
  },
  { deep: true },
);

const handleGenerate = async () => {
  if (!description.value.trim()) {
    window.toastr.warning('请输入条目描述');
    return;
  }

  try {
    isProcessing.value = true;
    progress.value = 0;
    window.toastr.info('正在生成世界书条目...');

    const systemPrompt = `你是一个专业的世界书条目设计师。请根据用户的描述生成一个世界书条目。

输出格式必须是 JSON，包含以下字段：
{
  "name": "条目名称",
  "content": "条目的详细内容",
  "keys": ["关键词1", "关键词2"]
}

要求：
1. 名称简洁明确
2. 内容详细且有条理
3. 关键词用于触发条目，应包含核心概念
4. 只输出 JSON，不要其他内容`;

    const messages = [
      { role: 'system', content: systemPrompt },
      { role: 'user', content: description.value },
    ];

    const result = await callAIWithTavernSupport(messages, settings.value, {
      onProgress: (p: number) => (progress.value = p),
    });

    // 解析 JSON
    try {
      const jsonMatch = result.match(/\{[\s\S]*\}/);
      if (jsonMatch) {
        const parsed = JSON.parse(jsonMatch[0]);
        output.value = {
          name: parsed.name || '未命名条目',
          content: parsed.content || '',
          strategy: {
            type: 'vectorized',
            keys: parsed.keys || [],
          },
        };
      } else {
        // 如果无法解析，使用原始文本
        output.value = {
          name: '生成的条目',
          content: result,
          strategy: { type: 'vectorized', keys: [] },
        };
      }
    } catch (parseError) {
      output.value = {
        name: '生成的条目',
        content: result,
        strategy: { type: 'vectorized', keys: [] },
      };
    }

    window.toastr.success('条目生成完成！');
  } catch (error) {
    console.error('世界书条目生成失败:', error);
    window.toastr.error(translateError(error, '生成'));
  } finally {
    isProcessing.value = false;
    progress.value = 0;
  }
};

const copyResult = () => {
  if (!output.value) return;
  const text = `【${output.value.name}】\n${output.value.content}`;
  copyToClipboard(text, '条目已复制');
};

const insertToWorldbook = async () => {
  if (!output.value || !selectedWorldbook.value) return;

  try {
    isInserting.value = true;
    const tav = (window as any).TavernHelper;

    if (tav?.createWorldbookEntries) {
      await tav.createWorldbookEntries(selectedWorldbook.value, [
        {
          name: output.value.name,
          content: output.value.content,
          keys: output.value.strategy?.keys || [],
          comment: '由猫猫工具自动生成',
          enabled: true,
        },
      ]);
      window.toastr.success('已插入到世界书');
    } else {
      window.toastr.error('TavernHelper API 不可用');
    }
  } catch (e) {
    console.error('插入失败:', e);
    window.toastr.error('插入失败');
  } finally {
    isInserting.value = false;
  }
};

const clearForm = () => {
  description.value = '';
  output.value = null;
};

defineExpose({
  setExpanded: (val: boolean) => (expanded.value = val),
  loadData: (data: any) => {
    if (data) {
      description.value = data.description || '';
      output.value = data.output || null;
      selectedWorldbook.value = data.selectedWorldbook || '';
    }
  },
});
</script>
